import{_ as t,C as i,o as e,c as o,j as n,a,E as r}from"./chunks/framework.BzQXgbNp.js";const k=JSON.parse('{"title":"2026 春节游山西","description":"","frontmatter":{"title":"2026 春节游山西","date":"2026-02-24T02:01:23.000Z","draft":false},"headers":[],"relativePath":"posts/shanxi.md","filePath":"posts/shanxi.md","lastUpdated":1783569911000}'),d={name:"posts/shanxi.md"};function p(m,l,u,x,f,b){const s=i("ImageGallery");return e(),o("div",null,[l[0]||(l[0]=n("p",null,"住：太原四天，行程虽然不全在太原，但决定不换酒店，避免背包奔波",-1)),l[1]||(l[1]=n("p",null,"吃：老太原铜火锅、老太原香酥鸡、刀削面、羊肉烧麦、糖醋丸子、过油肉、平遥牛肉、汾酒、麻酱毛肚、桂花小米凉糕，再推荐两家店“最爱妈妈菜”和“老下元烧烤”（23:00 再去大概率不用排队）",-1)),l[2]||(l[2]=n("p",null,"学：新认识两个字，并（Bīng）州和“隰（xí）县”",-1)),l[3]||(l[3]=n("p",null,"玩：山西博物院 + 钟楼街 + 晋祠 + 太原植物园 + 小西天 + 东湖醋园 + 迎泽公园 + 王家大院 + 双林寺 + 平遥古城",-1)),l[4]||(l[4]=n("hr",null,null,-1)),l[5]||(l[5]=n("h2",{id:"📍山西博物院-钟楼街",tabindex:"-1"},[a("📍山西博物院 + 钟楼街 "),n("a",{class:"header-anchor",href:"#📍山西博物院-钟楼街","aria-label":'Permalink to "📍山西博物院 + 钟楼街"'},"​")],-1)),l[6]||(l[6]=n("p",null,"忘了提前预约山西博物院，谁知刚到太原随手一刷，竟幸运捡漏。午饭后打车前往，这里的镇馆之宝是“晋侯鸟尊”，它不仅是西周青铜艺术的巅峰，也是山西省的标志。我们不到两个小时便转完了，然后去钟楼街溜达，看到了“黄盖玻汾汽水”和“老陈醋可乐”，都没有兴趣，买了个冰箱贴留念，便回酒店附近吃饭，热气腾腾的老太原铜火锅，味道确实不错。",-1)),r(s,{dir:"/images/shanxi/"}),l[7]||(l[7]=n("h2",{id:"📍晋祠-太原植物园",tabindex:"-1"},[a("📍晋祠 + 太原植物园 "),n("a",{class:"header-anchor",href:"#📍晋祠-太原植物园","aria-label":'Permalink to "📍晋祠 + 太原植物园"'},"​")],-1)),l[8]||(l[8]=n("p",null,"当地人说：“不到晋祠，不算到过太原”。睡到自然醒后，大概 11 点抵达晋祠。这里依山而建，离市区较远，是中国现存最早的皇家祭祀园林，园中宋代遗存的圣母殿、3000 岁的周柏、终年不息的难老泉被誉为“晋祠三绝”。大概转了四个小时后离开，打车去太原植物园。看过了热带与沙漠植物，因为时间还早，就没等天黑后的网红赛博朋克电梯。随后在手机上租了辆坦克300，取车后直奔“最爱妈妈菜”。他家的老太原香酥鸡，味道很棒。",-1)),r(s,{dir:"/images/shanxi/"}),l[9]||(l[9]=n("h2",{id:"📍小西天-东湖醋园-迎泽公园-午夜并州",tabindex:"-1"},[a("📍小西天 + 东湖醋园 + 迎泽公园 + 午夜并州 "),n("a",{class:"header-anchor",href:"#📍小西天-东湖醋园-迎泽公园-午夜并州","aria-label":'Permalink to "📍小西天 + 东湖醋园 + 迎泽公园 + 午夜并州"'},"​")],-1)),l[10]||(l[10]=n("p",null,"小西天原名千佛庵，由明代僧人兴建，距今已 400 多年，“庵”不像“寺”那样追求排场，这里虽没有完整的中轴线与钟鼓楼，却将修行环境做到了极致。千佛庵的大雄宝殿号称极乐世界的“样板间”，在不足 200 平米的空间内，布满了 1900 多尊彩塑，被誉为“中国悬塑艺术的绝唱”。层层叠叠的佛像与楼阁有从墙面上“飞”出来的感觉。作为《黑神话：悟空》中黄眉大王领地的原型，这里让我们期待已久。",-1)),l[11]||(l[11]=n("p",null,"凌晨 4 点带孩子准时出发，6:30 到达景区最近的停车场时已经快没车位，7:30 景区开门，工作人员提前放行，为抢第一波参观，我们决定“憋尿”冲锋，几分钟爬上小山头直抵大雄宝殿。大殿的建筑朝向较为特殊，为坐西向东，说是因为殿内供奉的是西方三圣和极乐世界景象，大门向东开寓意着众生从东方“婆娑世界”向往并迈向西方“极乐世界”。起初阳光未至，殿内光线昏暗，但殿内悬塑给人的感觉已足够震撼，脑中不禁响起黄眉那句：“既见未来，为何不拜？”，观赏拍照后走出来但舍不得走，和门口保洁师傅聊完得知 8 点过后阳光照进殿内时才是绝佳时刻。于是果断在门口守候，阳光抵达时我们再次入殿，这时里面已经挤满了人，在晨光映照下，殿内显得更加金碧辉煌，拍照观赏后心满意足地离开这里去上厕所。",-1)),l[12]||(l[12]=n("p",null,"回程时在服务区补觉半小时，回酒店和家人吃完麦当劳后直奔东湖醋园，参观下传统老陈醋生产工艺，进入发酵区后，那股浓烈、醇厚的醋味直冲脑门，瞬间不困了。据说老太原人感冒了来这儿“熏一熏”能好一半，参观后也快到还车时间了，于是先把家人送往太原最大的“城市客厅”迎泽公园，让他们在湖光古建中感受下地道的太原慢生活。",-1)),l[13]||(l[13]=n("p",null,"为了拍摄“五彩斑斓”的小区彩灯，晚上自己出门打车，司机带我绕中环大半圈，虽然车费过百，但拍到满意画面后还是觉得值了。22:30 抵达老下元烧烤，依然需要排队，不过它家“麻酱毛肚”和“肉串”味道都还不错。半斤汾酒下肚，晕晕乎乎步行三公里回酒店。",-1)),r(s,{dir:"/images/shanxi/"}),l[14]||(l[14]=n("h2",{id:"📍王家大院-双林寺-平遥古城",tabindex:"-1"},[a("📍王家大院 + 双林寺 + 平遥古城 "),n("a",{class:"header-anchor",href:"#📍王家大院-双林寺-平遥古城","aria-label":'Permalink to "📍王家大院 + 双林寺 + 平遥古城"'},"​")],-1)),l[15]||(l[15]=n("p",null,"王家大院历经 300 多年建成，一直以来有“王家归来不看院”的说法，号称民居里的“故宫”。最硬核看点是这里的三雕艺术（砖、木、石），非常精美，也刻满了寓意，体现了王家“商而优则仕”的财富和规矩。",-1)),l[16]||(l[16]=n("p",null,"从太原去王家大院需要坐 40 多分钟高铁，为避开人流，将车票时间由 10 点改签至 6:50。即便 8 点抵达景区，游客仍然很多。我们大概一个小时就逛完了，比预期要快，于是再次改签去平遥古城站的高铁，然后焦急地等孩子拉完屎后离开景区，高铁经 16 分钟后到达，然后打车去双林寺。只为一睹那尊“全国最帅韦驮”。彩塑韦驮似乎有点儿骨盆前倾，而且不管你站在哪个角度看，他的眼神都在盯着你。",-1)),l[17]||(l[17]=n("p",null,"逛完双林寺后打车去平遥古城，进城先找饭馆，用一瓶平遥啤酒、两盘平遥牛肉、两盘煎包、一人一碗刀削面填饱肚子后，开始沿街溜达，先去了“日升昌票号”，这是中国第一家银行，当年的防伪技术放到全世界都算牛的。接着去了“协同庆票号”看地下金库。日升昌像是行业里的“老大哥”，协同庆则是“后起之秀”和“营销天才”。它家老板以前是卖绸缎和开面馆的，但特别懂用人，他打破了晋商“只用老乡”的传统，谁有本事就用谁，这种开放的经营理念让它在短短几十年内就成为了顶级票号。我们过了 18:00 点才到达平遥县衙，已错过营业时间，就在附近买了三杯蜜雪冰城后出城等待晚上八点的灯光秀，同时也把晚上十点的高铁票改签到 21:17，等待期间我和妈把几乎没喝的饮料都给了孩子，他连同自己那份喝完后连上了三趟厕所...灯光秀感觉很一般，看完打车去车站，大概半小时回到太原。第二天睡到自然醒，中午吃饱喝足后，坐车回家。",-1)),r(s,{dir:"/images/shanxi/"})])}const P=t(d,[["render",p]]);export{k as __pageData,P as default};
